2	8488	49	2026-02-06 07:29:00.773566	111	321	# 테스트 케이스 개수 입력\r\nT = int(input())\r\n\r\nfor test_case in range(1, T + 1):\r\n    # 명령의 개수 N 입력\r\n    N = int(input())\r\n    \r\n    stack = []   # 가방 역할을 하는 스택 (LIFO)\r\n    result = []  # '?' 명령의 결과를 저장할 리스트\r\n    \r\n    for _ in range(N):\r\n        # 명령어를 입력받아 공백 기준으로 나눔\r\n        command = input().split()\r\n        op = command[0] # 연산자 (+, -, ?)\r\n        \r\n        if op == '+':\r\n            # + X: 가방에 공책 X를 넣음 (push)\r\n            # 숫자를 문자열 그대로 저장해도 출력엔 문제 없음\r\n            stack.append(command[1])\r\n            \r\n        elif op == '-':\r\n            # -: 가방에서 마지막 공책을 꺼냄 (pop)\r\n            # 공책이 없으면(스택이 비었으면) 아무 일도 일어나지 않음\r\n            if stack:\r\n                stack.pop()\r\n                \r\n        elif op == '?':\r\n            # ?: 마지막 공책 확인 (peek)\r\n            if stack:\r\n                result.append(stack[-1])\r\n            else:\r\n                # 공책이 없으면 -1\r\n                result.append("-1")\r\n    \r\n    # 결과 출력 (공백으로 구분하여 출력)\r\n    print(f'#{test_case} {" ".join(result)}')	### ✅ 결과 - **끝까지 스스로 점검하며 마무리한 게 정말 좋아!** ### 🔍 앞으로 생각해볼 것 - **과정 기록이 거의 없어서** 자주 실수한 지점을 딱 집기 어려워. 대신 풀이 시간이 아주 짧아서, 다음엔 **스스로 푼 과정**(중간 생각/메모)을 남기며 풀어보면 실력이 더 빨리 늘어. ### 🛠 다음에 해볼 것 - **작은 입력 1개**로 손으로 따라가며 중간값을 체크해봐. - 같은 실수가 나오면, 그 줄 바로 위/아래에서 변수 값 변화를 한 줄로	PYTHON	SUCCESS
