0	4192	40	2026-02-06 07:31:06.715476	116	326	# 20 버스 정류장의 승차 표 관리\r\n획득 점수 150점\r\n메모리 제한 128MiB\r\n알고리즘 스택\r\n실행 제한 시간 5초\r\n원빈이는 버스 정류장의 표 보관함에 승차 표를 관리하는 프로그램을 만들어 보려고 해요.\r\n각 명령을 처리할 때마다 특정 작업을 수행해야 해요.\r\n'+ X'는 X를 추가, '-'는 마지막 표를 제거, '?'는 마지막 표를 출력해요.\r\n만약 표가 없으면 -1을 출력해요.\r\n모든 '?' 명령의 결과를 순서대로 모아 출력해 주세요.\r\n각 테스트케이스의 결과는 공백으로 구분해 한 줄로 표시해요.\r\n예를 들어, ? + 1 + 2 + 3 - ? 는 -1 2 가 정답이에요.\r\n입력 설명\r\n첫 줄에 테스트케이스 개수 T가 주어져요.\r\n각 테스트케이스마다 첫 줄에 명령의 개수 N이 주어져요.\r\n이후 N줄에 걸쳐 각 명령이 주어지며, 명령은 '+ X', '-', '?' 중 하나예요.\r\n출력 설명\r\n각 테스트케이스마다 한 줄씩 출력해요.\r\n출력 형식은 '#케이스번호 결과들'이에요.\r\n결과들은 공백으로 구분해요.\r\n예제 입력\r\n1\r\n45\r\n?\r\n?\r\n+ 369\r\n+ 177\r\n-\r\n+ 580\r\n-\r\n?\r\n?\r\n?\r\n+ -558\r\n+ 849\r\n?\r\n-\r\n+ 820\r\n-\r\n?\r\n?\r\n?\r\n?\r\n+ 416\r\n+ -387\r\n?\r\n?\r\n+ 43\r\n-\r\n?\r\n+ -466\r\n?\r\n-\r\n+ 20\r\n?\r\n-\r\n?\r\n+ 487\r\n+ -499\r\n?\r\n?\r\n+ -135\r\n+ -48\r\n+ 217\r\n?\r\n+ 417\r\n+ 294\r\n?\r\n예제 출력\r\n#1 -1 -1 369 369 369 849 -558 -558 -558 -558 -387 -387 -387 -466 20 -387 -499 -499 217 294	\N	PYTHON	FAIL
1	8512	63	2026-02-06 07:33:23.84649	118	330	import sys\r\nfrom collections import deque\r\n\r\n# 대량의 입력을 빠르게 받기 위해 sys.stdin.readline 사용\r\ninput = sys.stdin.readline\r\n\r\nT = int(input())\r\n\r\nfor test_case in range(1, T + 1):\r\n    # 명령의 개수 N 입력\r\n    try:\r\n        line = input().strip()\r\n        if not line: # 공백 라인이 들어올 경우 방지\r\n            line = input().strip()\r\n        N = int(line)\r\n    except ValueError:\r\n        break\r\n        \r\n    # 큐 생성 (deque 사용)\r\n    q = deque()\r\n    \r\n    # [최적화] 케이스 번호를 먼저 출력하고 줄바꿈 방지\r\n    print(f'#{test_case}', end='')\r\n    \r\n    for _ in range(N):\r\n        command = input().split()\r\n        op = command[0]\r\n        \r\n        if op == '+':\r\n            # + X: 피자 조각 추가 (Enqueue)\r\n            # 숫자로 변환할 필요 없이 문자열 그대로 저장 (출력만 하면 되므로)\r\n            q.append(command[1])\r\n            \r\n        elif op == '-':\r\n            # -: 맨 앞 조각 제거 (Dequeue)\r\n            # 큐가 비어있지 않을 때만 제거\r\n            if q:\r\n                q.popleft()\r\n                \r\n        elif op == '?':\r\n            # ?: 맨 앞 조각 확인 (Peek)\r\n            # 결과를 리스트에 담지 않고 '즉시 출력'하여 메모리 절약\r\n            if q:\r\n                # 앞에 공백을 포함하여 출력\r\n                print(f' {q[0]}', end='')\r\n            else:\r\n                # 비어있으면 -1 출력\r\n                print(' -1', end='')\r\n    \r\n    # 하나의 테스트 케이스가 끝나면 줄바꿈\r\n    print()	### ✅ 결과 - **끝까지 스스로 점검하며 마무리한 게 정말 좋아!** ### 🔍 앞으로 생각해볼 것 - **과정 기록이 거의 없어서** 자주 실수한 지점을 딱 집기 어려워. 대신 풀이 시간이 아주 짧아서, 다음엔 **스스로 푼 과정**(중간 생각/메모)을 남기며 풀어보면 실력이 더 빨리 늘어. ### 🛠 다음에 해볼 것 - **작은 입력 1개**로 손으로 따라가며 중간값을 체크해봐. - 같은 실수가 나오면, 그 줄 바로 위/아래에서 변수 값 변화를 한 줄로	PYTHON	SUCCESS
