1	8448	58	2026-02-06 07:36:05.470473	120	334	import sys\r\nfrom collections import deque\r\n\r\n# 대량의 명령 처리를 위해 빠른 입력 사용\r\ninput = sys.stdin.readline\r\n\r\n# 테스트 케이스 개수 T 입력\r\ntry:\r\n    line = input().strip()\r\n    if line:\r\n        T = int(line)\r\n    else:\r\n        T = 0\r\nexcept ValueError:\r\n    T = 0\r\n\r\nfor test_case in range(1, T + 1):\r\n    try:\r\n        line = input().strip()\r\n        while not line: # 빈 줄 건너뛰기\r\n            line = input().strip()\r\n        N = int(line)\r\n    except ValueError:\r\n        break\r\n        \r\n    # 시간 복잡도 O(1)을 위해 deque 사용\r\n    q = deque()\r\n    \r\n    # 케이스 번호 먼저 출력 (줄바꿈 없이)\r\n    print(f'#{test_case}', end='')\r\n    \r\n    for _ in range(N):\r\n        command = input().split()\r\n        op = command[0]\r\n        \r\n        if op == '+':\r\n            # + X: 맨 뒤에 박스 추가\r\n            q.append(command[1])\r\n            \r\n        elif op == '-':\r\n            # -: 맨 앞의 박스 제거\r\n            # 큐가 비어있지 않을 때만 제거\r\n            if q:\r\n                q.popleft()\r\n                \r\n        elif op == '?':\r\n            # ?: 맨 앞의 박스 값 확인\r\n            # 메모리 초과 방지를 위해 리스트에 저장하지 않고 즉시 출력\r\n            if q:\r\n                print(f' {q[0]}', end='')\r\n            else:\r\n                print(' -1', end='')\r\n                \r\n    # 케이스 종료 후 줄바꿈\r\n    print()	### ✅ 결과 - **끝까지 스스로 점검하며 마무리한 게 정말 좋아!** ### 🔍 앞으로 생각해볼 것 - **과정 기록이 거의 없어서** 자주 실수한 지점을 딱 집기 어려워. 대신 풀이 시간이 아주 짧아서, 다음엔 **스스로 푼 과정**(중간 생각/메모)을 남기며 풀어보면 실력이 더 빨리 늘어. ### 🛠 다음에 해볼 것 - **작은 입력 1개**로 손으로 따라가며 중간값을 체크해봐. - 같은 실수가 나오면, 그 줄 바로 위/아래에서 변수 값 변화를 한 줄로	PYTHON	SUCCESS
0	8468	50	2026-02-06 07:39:53.216779	124	338	import sys\r\n\r\ndef solve():\r\n    # 입력 속도를 높이기 위해 sys.stdin.read를 사용합니다.\r\n    input_data = sys.stdin.read().split()\r\n    if not input_data:\r\n        return\r\n    \r\n    idx = 0\r\n    T_str = input_data[idx]\r\n    T = int(T_str)\r\n    idx += 1\r\n    \r\n    for t in range(1, T + 1):\r\n        N = int(input_data[idx])\r\n        idx += 1\r\n        \r\n        stack = []\r\n        results = []\r\n        \r\n        for _ in range(N):\r\n            command = input_data[idx]\r\n            idx += 1\r\n            \r\n            if command == '+':\r\n                # '+ X' 형태이므로 다음 요소인 X를 가져와 스택에 넣습니다.\r\n                value = input_data[idx]\r\n                idx += 1\r\n                stack.append(value)\r\n                \r\n            elif command == '-':\r\n                # 스택이 비어있지 않을 때만 마지막 요소를 제거합니다.\r\n                if stack:\r\n                    stack.pop()\r\n                    \r\n            elif command == '?':\r\n                # 스택이 비어있으면 -1, 있으면 가장 마지막 요소를 저장합니다.\r\n                if not stack:\r\n                    results.append("-1")\r\n                else:\r\n                    results.append(stack[-1])\r\n        \r\n        # 결과 출력 형식: #케이스번호 결과들\r\n        print(f"#{t} {' '.join(results)}")\r\n\r\nif __name__ == "__main__":\r\n    solve()	### ✅ 결과 - **끝까지 스스로 점검하며 마무리한 게 정말 좋아!** ### 🔍 앞으로 생각해볼 것 - **과정 기록이 거의 없어서** 자주 실수한 지점을 딱 집기 어려워. 대신 풀이 시간이 아주 짧아서, 다음엔 **스스로 푼 과정**(중간 생각/메모)을 남기며 풀어보면 실력이 더 빨리 늘어. ### 🛠 다음에 해볼 것 - **작은 입력 1개**로 손으로 따라가며 중간값을 체크해봐. - 같은 실수가 나오면, 그 줄 바로 위/아래에서 변수 값 변화를 한 줄로	PYTHON	SUCCESS
0	8572	49	2026-02-06 07:41:18.497701	126	340	import sys\r\nfrom collections import deque\r\n\r\ndef solve():\r\n    # 입력을 빠르게 받기 위해 전체를 읽어옵니다.\r\n    input_data = sys.stdin.read().split()\r\n    if not input_data:\r\n        return\r\n    \r\n    idx = 0\r\n    T = int(input_data[idx])\r\n    idx += 1\r\n    \r\n    for t in range(1, T + 1):\r\n        N = int(input_data[idx])\r\n        idx += 1\r\n        \r\n        # 큐(Queue)를 생성합니다.\r\n        queue = deque()\r\n        results = []\r\n        \r\n        for _ in range(N):\r\n            command = input_data[idx]\r\n            idx += 1\r\n            \r\n            if command == '+':\r\n                # '+ X' 명령: 뒤에 추가\r\n                value = input_data[idx]\r\n                idx += 1\r\n                queue.append(value)\r\n                \r\n            elif command == '-':\r\n                # '-' 명령: 맨 앞의 박스를 제거\r\n                if queue:\r\n                    queue.popleft()\r\n                    \r\n            elif command == '?':\r\n                # '?' 명령: 맨 앞의 박스 확인\r\n                if not queue:\r\n                    results.append("-1")\r\n                else:\r\n                    results.append(queue[0])\r\n        \r\n        # 결과 출력 형식: #케이스번호 결과들\r\n        if results:\r\n            print(f"#{t} {' '.join(results)}")\r\n        else:\r\n            # 결과값이 없으면 빈 줄(케이스 번호만) 출력\r\n            print(f"#{t}")\r\n\r\nif __name__ == "__main__":\r\n    solve()	### ✅ 결과 - **끝까지 스스로 점검하며 마무리한 게 정말 좋아!** ### 🔍 앞으로 생각해볼 것 - **과정 기록이 거의 없어서** 자주 실수한 지점을 딱 집기 어려워. 대신 풀이 시간이 아주 짧아서, 다음엔 **스스로 푼 과정**(중간 생각/메모)을 남기며 풀어보면 실력이 더 빨리 늘어. ### 🛠 다음에 해볼 것 - **작은 입력 1개**로 손으로 따라가며 중간값을 체크해봐. - 같은 실수가 나오면, 그 줄 바로 위/아래에서 변수 값 변화를 한 줄로	PYTHON	SUCCESS
